# -*- coding: utf-8 -*-
import sys
import io
sys.stdout = io.TextIOWrapper(sys.stdout.buffer, encoding='utf-8')
import json
import re

# Читаем файл
with open('src/config/company.ts', 'r', encoding='utf-8') as f:
    content = f.read()

# Шаг 1: Заменяем МетизОпт на KRP
content = content.replace('| МетизОпт', '| KRP')

# Шаг 2: Добавляем fullDescription для каждой категории
# Извлекаем массив categories
match = re.search(r'categories: \[(.*?)\],\s*faq:', content, re.DOTALL)
if not match:
    print("ERROR: Could not find categories array")
    sys.exit(1)

categories_str = match.group(1)

