# Для каждого slug добавляем fullDescription
for slug, desc in descriptions.items():
    # Ищем строку, начинающуюся с этого slug
    pattern = rf'(\{{ slug: "{slug}",.*?, metaDesc: "[^"]*")'

    def replacer(match):
        line = match.group(1)
        # Добавляем fullDescription в конец, перед }
        escaped_desc = desc.replace('"', '\\"')
        return line + f', fullDescription: "{escaped_desc}"'

    categories_str = re.sub(pattern, replacer, categories_str, flags=re.DOTALL)

# Заменяем в содержимом
content = content.replace('categories: [' + match.group(1), 'categories: [' + categories_str)

# Сохраняем
with open('src/config/company.ts', 'w', encoding='utf-8') as f:
    f.write(content)

print("Done: KRP branding + fullDescriptions added")
